use crate::council::types::MergeOutcome;
use anyhow::{Context, Result};
use git2::Repository;
use std::fs;
use std::io::Write;
use std::path::{Path, PathBuf};
use std::process::{Command, Output, Stdio};

pub struct WorktreeManager {
    repo: Repository,
    repo_path: PathBuf,
}

impl WorktreeManager {
    pub fn new(repo_path: &Path) -> Result<Self> {
        let repo = Repository::open(repo_path).context("Failed to open git repository")?;
        let repo_path = repo
            .workdir()
            .map(Path::to_path_buf)
            .or_else(|| repo.path().parent().map(Path::to_path_buf))
            .context("Git repository does not have a usable working directory")?;

        Ok(Self { repo, repo_path })
    }

    pub fn create_worktree(&self, name: &str) -> Result<PathBuf> {
        let worktree_path = self.worktree_path(name);
        let worktree_root = self.worktree_root();
        fs::create_dir_all(&worktree_root).with_context(|| {
            format!(
                "Failed to create council worktree directory at {}",
                worktree_root.display()
            )
        })?;

        let output = Command::new("git")
            .args(["worktree", "add", "--detach"])
            .arg(&worktree_path)
            .arg("HEAD")
            .current_dir(&self.repo_path)
            .output()
            .context("Failed to create git worktree")?;

        self.ensure_git_success(
            output,
            format!(
                "Git worktree creation failed for {}",
                worktree_path.display()
            ),
        )?;

        Ok(worktree_path)
    }

    pub fn remove_worktree(&self, name: &str) -> Result<()> {
        let worktree_path = self.worktree_path(name);
        if !worktree_path.exists() {
            self.prune_worktrees()?;
            self.remove_worktree_root_if_empty()?;
            return Ok(());
        }

        let output = Command::new("git")
            .args(["worktree", "remove", "--force"])
            .arg(&worktree_path)
            .current_dir(&self.repo_path)
            .output()
            .context("Failed to remove git worktree")?;

        self.ensure_git_success(
            output,
            format!(
                "Git worktree removal failed for {}",
                worktree_path.display()
            ),
        )?;

        self.prune_worktrees()?;
        self.remove_worktree_root_if_empty()?;
        Ok(())
    }

    pub fn cleanup_all(&self) -> Result<()> {
        let worktree_root = self.worktree_root();
        if !worktree_root.exists() {
            self.prune_worktrees()?;
            return Ok(());
        }

        for entry in fs::read_dir(&worktree_root).with_context(|| {
            format!(
                "Failed to list council worktrees in {}",
                worktree_root.display()
            )
        })? {
            let entry = entry.with_context(|| {
                format!(
                    "Failed to read council worktree entry in {}",
                    worktree_root.display()
                )
            })?;

            if !entry
                .file_type()
                .with_context(|| format!("Failed to inspect {}", entry.path().display()))?
                .is_dir()
            {
                continue;
            }

            let name = entry.file_name();
            let name = name.to_string_lossy();
            self.remove_worktree(&name)?;
        }

        self.prune_worktrees()?;
        self.remove_worktree_root_if_empty()?;
        Ok(())
    }

    pub fn generate_diff(&self, worktree_path: &Path) -> Result<String> {
        let output = Command::new("git")
            .args(["diff", "HEAD"])
            .current_dir(worktree_path)
            .output()
            .context("Failed to generate git diff")?;

        self.git_stdout(
            output,
            format!("Git diff generation failed for {}", worktree_path.display()),
        )
    }

    fn worktree_root(&self) -> PathBuf {
        self.repo_path.join(".forge").join("council-worktrees")
    }

    fn worktree_path(&self, name: &str) -> PathBuf {
        self.worktree_root().join(name)
    }

    fn prune_worktrees(&self) -> Result<()> {
        let output = Command::new("git")
            .args(["worktree", "prune"])
            .current_dir(&self.repo_path)
            .output()
            .context("Failed to prune git worktrees")?;

        self.ensure_git_success(output, "Git worktree prune failed".to_string())
    }

    fn remove_worktree_root_if_empty(&self) -> Result<()> {
        let worktree_root = self.worktree_root();
        if !worktree_root.exists() {
            return Ok(());
        }

        let mut entries = fs::read_dir(&worktree_root).with_context(|| {
            format!(
                "Failed to inspect council worktree directory at {}",
                worktree_root.display()
            )
        })?;

        if entries.next().is_none() {
            fs::remove_dir(&worktree_root).with_context(|| {
                format!(
                    "Failed to remove empty council worktree directory at {}",
                    worktree_root.display()
                )
            })?;
        }

        Ok(())
    }

    fn git_stdout(&self, output: std::process::Output, message: String) -> Result<String> {
        let _ = &self.repo;
        if !output.status.success() {
            let stderr = String::from_utf8_lossy(&output.stderr);
            let stdout = String::from_utf8_lossy(&output.stdout);
            anyhow::bail!("{message}: {}\n{}", stderr.trim(), stdout.trim())
        }

        String::from_utf8(output.stdout).context(message)
    }

    fn ensure_git_success(&self, output: std::process::Output, message: String) -> Result<()> {
        let _ = &self.repo;
        if output.status.success() {
            return Ok(());
        }

        let stderr = String::from_utf8_lossy(&output.stderr);
        let stdout = String::from_utf8_lossy(&output.stdout);
        anyhow::bail!("{message}: {}\n{}", stderr.trim(), stdout.trim())
    }
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
pub struct PatchSet {
    files: Vec<FilePatch>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct FilePatch {
    path: String,
    diff: String,
}

impl PatchSet {
    pub fn parse(diff: &str) -> Result<Self> {
        if diff.trim().is_empty() {
            return Ok(Self::default());
        }

        let mut files = Vec::new();
        let mut current_path: Option<String> = None;
        let mut current_diff = String::new();

        for chunk in diff.split_inclusive('\n') {
            if chunk.starts_with("diff --git ") {
                if let Some(path) = current_path.take() {
                    files.push(FilePatch {
                        path,
                        diff: std::mem::take(&mut current_diff),
                    });
                } else if !current_diff.trim().is_empty() {
                    anyhow::bail!("Malformed diff: content found before first file header");
                }

                current_path = Some(parse_diff_header_path(chunk.trim_end())?);
            }

            current_diff.push_str(chunk);
        }

        if let Some(path) = current_path {
            files.push(FilePatch {
                path,
                diff: current_diff,
            });
        } else {
            anyhow::bail!("Malformed diff: missing diff --git file header");
        }

        Ok(Self { files })
    }

    pub fn files_changed(&self) -> Vec<&str> {
        self.files.iter().map(|file| file.path.as_str()).collect()
    }

    pub fn is_empty(&self) -> bool {
        self.files.is_empty()
    }
}

fn parse_diff_header_path(header: &str) -> Result<String> {
    let remainder = header
        .strip_prefix("diff --git ")
        .with_context(|| format!("Malformed diff header: {header}"))?;
    let (_, path) = remainder
        .rsplit_once(" b/")
        .with_context(|| format!("Malformed diff header: {header}"))?;

    Ok(path.to_string())
}

pub fn apply_patch(repo_path: &Path, patch: &str) -> Result<MergeOutcome> {
    if patch.trim().is_empty() {
        return Ok(MergeOutcome::Clean(String::new()));
    }

    let check_output = run_git_with_input(repo_path, ["apply", "--check", "-"], patch)
        .context("Failed to validate patch with git apply --check")?;
    if !check_output.status.success() {
        let existing_diff =
            git_diff_head(repo_path).context("Failed to inspect working tree for conflicts")?;
        let conflicts = detect_conflicts(&existing_diff, patch);
        if !conflicts.is_empty() {
            return Ok(MergeOutcome::Conflict(conflicts));
        }

        return Ok(MergeOutcome::Failure(git_error_message(
            "git apply --check failed",
            &check_output,
        )));
    }

    let apply_output = run_git_with_input(repo_path, ["apply", "-"], patch)
        .context("Failed to apply patch with git apply")?;
    if !apply_output.status.success() {
        return Ok(MergeOutcome::Failure(git_error_message(
            "git apply failed",
            &apply_output,
        )));
    }

    Ok(MergeOutcome::Clean(patch.to_string()))
}

pub fn detect_conflicts(patch_a: &str, patch_b: &str) -> Vec<String> {
    let patch_a_files = parse_patch_regions(patch_a);
    let patch_b_files = parse_patch_regions(patch_b);
    let mut conflicts = Vec::new();

    for file_a in &patch_a_files {
        for file_b in &patch_b_files {
            if file_a.path != file_b.path {
                continue;
            }

            let overlaps = if file_a.hunks.is_empty() || file_b.hunks.is_empty() {
                true
            } else {
                file_a.hunks.iter().any(|hunk_a| {
                    file_b
                        .hunks
                        .iter()
                        .any(|hunk_b| hunks_overlap(*hunk_a, *hunk_b))
                })
            };

            if overlaps && !conflicts.contains(&file_a.path) {
                conflicts.push(file_a.path.clone());
            }
        }
    }

    conflicts
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct PatchRegions {
    path: String,
    hunks: Vec<HunkRange>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct HunkRange {
    start: u32,
    len: u32,
}

fn git_diff_head(repo_path: &Path) -> Result<String> {
    let output = Command::new("git")
        .args(["diff", "HEAD"])
        .current_dir(repo_path)
        .output()
        .context("Failed to generate git diff")?;

    if !output.status.success() {
        anyhow::bail!("{}", git_error_message("git diff HEAD failed", &output));
    }

    String::from_utf8(output.stdout).context("git diff HEAD produced invalid UTF-8")
}

fn run_git_with_input<const N: usize>(
    repo_path: &Path,
    args: [&str; N],
    input: &str,
) -> Result<Output> {
    let mut child = Command::new("git")
        .args(args)
        .current_dir(repo_path)
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .with_context(|| format!("Failed to launch git {:?}", args))?;

    if let Some(stdin) = child.stdin.as_mut() {
        stdin
            .write_all(input.as_bytes())
            .with_context(|| format!("Failed to write patch input to git {:?}", args))?;
    }

    child
        .wait_with_output()
        .with_context(|| format!("Failed to read git {:?} output", args))
}

fn git_error_message(prefix: &str, output: &Output) -> String {
    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();

    match (stderr.is_empty(), stdout.is_empty()) {
        (false, true) => format!("{prefix}: {stderr}"),
        (true, false) => format!("{prefix}: {stdout}"),
        (false, false) => format!("{prefix}: {stderr}\n{stdout}"),
        (true, true) => prefix.to_string(),
    }
}

fn parse_patch_regions(diff: &str) -> Vec<PatchRegions> {
    let mut files = Vec::new();
    let mut current_path: Option<String> = None;
    let mut current_hunks = Vec::new();

    for line in diff.lines() {
        if line.starts_with("diff --git ") {
            if let Some(path) = current_path.take() {
                files.push(PatchRegions {
                    path,
                    hunks: std::mem::take(&mut current_hunks),
                });
            }

            current_path = parse_diff_header_path(line).ok();
            continue;
        }

        if line.starts_with("@@ ") || line.starts_with("@@ -") {
            if let Some(range) = parse_hunk_range(line) {
                current_hunks.push(range);
            }
        }
    }

    if let Some(path) = current_path {
        files.push(PatchRegions {
            path,
            hunks: current_hunks,
        });
    }

    files
}

fn parse_hunk_range(header: &str) -> Option<HunkRange> {
    let remainder = header.strip_prefix("@@ -")?;
    let (old_range, _) = remainder.split_once(" +")?;
    let (start, len) = match old_range.split_once(',') {
        Some((start, len)) => (start, len),
        None => (old_range, "1"),
    };

    Some(HunkRange {
        start: start.parse().ok()?,
        len: len.parse().ok()?,
    })
}

fn hunks_overlap(a: HunkRange, b: HunkRange) -> bool {
    let a_end = a.start.saturating_add(a.len.max(1));
    let b_end = b.start.saturating_add(b.len.max(1));

    a.start < b_end && b.start < a_end
}

