//! Budget tracking for autoresearch experiment loops.
//!
//! Enforces a total spend cap by estimating cost from token counts and
//! model-specific pricing, persisting spend data for resume, and providing
//! a [`BudgetTracker::can_afford`] gate before each experiment.

use anyhow::{Context, Result};
use serde::{Deserialize, Serialize};

/// Pricing tiers for supported LLM models.
///
/// Prices are in USD per million tokens.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ModelPricing {
    pub model_name: String,
    pub input_price_per_mtok: f64,
    pub output_price_per_mtok: f64,
}

impl ModelPricing {
    /// Claude Sonnet approximate pricing.
    pub fn claude_sonnet() -> Self {
        Self {
            model_name: "claude-sonnet".to_string(),
            input_price_per_mtok: 3.0,
            output_price_per_mtok: 15.0,
        }
    }

    /// GPT 5.4 approximate pricing.
    pub fn gpt_5_4() -> Self {
        Self {
            model_name: "gpt-5.4".to_string(),
            input_price_per_mtok: 2.0,
            output_price_per_mtok: 8.0,
        }
    }

    /// Estimate cost for a single call given token counts.
    pub fn estimate_cost(&self, input_tokens: u32, output_tokens: u32) -> f64 {
        let input_cost = (input_tokens as f64 / 1_000_000.0) * self.input_price_per_mtok;
        let output_cost = (output_tokens as f64 / 1_000_000.0) * self.output_price_per_mtok;
        input_cost + output_cost
    }
}

/// A single cost record for one LLM call.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CostRecord {
    pub model: String,
    pub input_tokens: u32,
    pub output_tokens: u32,
    pub estimated_cost_usd: f64,
    pub description: String,
}

/// Tracks cumulative spend and enforces a budget cap.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BudgetTracker {
    /// Maximum allowed spend in USD.
    pub budget_cap_usd: f64,
    /// Running total of estimated spend in USD.
    pub total_spent_usd: f64,
    /// Individual cost records (for audit trail).
    pub records: Vec<CostRecord>,
}

impl BudgetTracker {
    /// Create a new tracker with the given budget cap.
    pub fn new(budget_cap_usd: f64) -> Self {
        Self {
            budget_cap_usd,
            total_spent_usd: 0.0,
            records: Vec::new(),
        }
    }

    /// Check if there is enough budget remaining for an estimated cost.
    pub fn can_afford(&self, estimated_cost: f64) -> bool {
        self.total_spent_usd + estimated_cost <= self.budget_cap_usd
    }

    /// Remaining budget in USD, floored at zero.
    pub fn remaining(&self) -> f64 {
        (self.budget_cap_usd - self.total_spent_usd).max(0.0)
    }

    /// Record a cost. Returns error if this would exceed the budget cap.
    pub fn record_cost(
        &mut self,
        model: &str,
        input_tokens: u32,
        output_tokens: u32,
        pricing: &ModelPricing,
        description: &str,
    ) -> Result<f64> {
        let cost = pricing.estimate_cost(input_tokens, output_tokens);
        if self.total_spent_usd + cost > self.budget_cap_usd {
            anyhow::bail!(
                "Budget exceeded: ${:.4} would bring total to ${:.4}, cap is ${:.2}",
                cost,
                self.total_spent_usd + cost,
                self.budget_cap_usd
            );
        }
        self.total_spent_usd += cost;
        self.records.push(CostRecord {
            model: model.to_string(),
            input_tokens,
            output_tokens,
            estimated_cost_usd: cost,
            description: description.to_string(),
        });
        Ok(cost)
    }

    /// Restore budget state from a previous experiment count.
    ///
    /// Each row in results.tsv represents one experiment that cost approximately
    /// `avg_cost_per_experiment`. This allows resuming a run without exact cost records.
    pub fn restore_from_experiment_count(
        &mut self,
        experiment_count: usize,
        avg_cost_per_experiment: f64,
    ) {
        let restored_spend = experiment_count as f64 * avg_cost_per_experiment;
        self.total_spent_usd = restored_spend;
    }

    /// Serialize to JSON for persistence.
    pub fn to_json(&self) -> Result<String> {
        serde_json::to_string_pretty(self).context("Failed to serialize BudgetTracker")
    }

    /// Deserialize from JSON.
    pub fn from_json(json: &str) -> Result<Self> {
        serde_json::from_str(json).context("Failed to deserialize BudgetTracker")
    }

    /// Save to a file path.
    pub fn save(&self, path: &std::path::Path) -> Result<()> {
        let json = self.to_json()?;
        std::fs::write(path, json).context("Failed to write budget tracker file")?;
        Ok(())
    }

    /// Load from a file path. Returns `None` if file does not exist.
    pub fn load(path: &std::path::Path) -> Result<Option<Self>> {
        if !path.exists() {
            return Ok(None);
        }
        let content =
            std::fs::read_to_string(path).context("Failed to read budget tracker file")?;
        let tracker = Self::from_json(&content)?;
        Ok(Some(tracker))
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // --- BudgetTracker::new defaults ---

    #[test]
    fn test_budget_tracker_new_defaults() {
        let tracker = BudgetTracker::new(25.0);
        assert!((tracker.budget_cap_usd - 25.0).abs() < f64::EPSILON);
        assert!((tracker.total_spent_usd - 0.0).abs() < f64::EPSILON);
        assert!(tracker.records.is_empty());
        assert!((tracker.remaining() - 25.0).abs() < f64::EPSILON);
    }

    // --- ModelPricing::estimate_cost ---

    #[test]
    fn test_model_pricing_estimate_cost_claude() {
        let pricing = ModelPricing::claude_sonnet();
        // 10,000 input tokens at $3/MTok = $0.03
        // 2,000 output tokens at $15/MTok = $0.03
        // Total = $0.06
        let cost = pricing.estimate_cost(10_000, 2_000);
        assert!(
            (cost - 0.06).abs() < 0.0001,
            "expected ~$0.06, got ${:.6}",
            cost
        );
    }

    #[test]
    fn test_model_pricing_estimate_cost_gpt() {
        let pricing = ModelPricing::gpt_5_4();
        // 10,000 input tokens at $2/MTok = $0.02
        // 2,000 output tokens at $8/MTok = $0.016
        // Total = $0.036
        let cost = pricing.estimate_cost(10_000, 2_000);
        assert!(
            (cost - 0.036).abs() < 0.0001,
            "expected ~$0.036, got ${:.6}",
            cost
        );
    }

    #[test]
    fn test_model_pricing_zero_tokens() {
        let pricing = ModelPricing::claude_sonnet();
        let cost = pricing.estimate_cost(0, 0);
        assert!((cost - 0.0).abs() < f64::EPSILON);
    }

    // --- BudgetTracker::can_afford ---

    #[test]
    fn test_can_afford_within_budget() {
        let tracker = BudgetTracker::new(1.0);
        assert!(tracker.can_afford(0.50));
        assert!(tracker.can_afford(1.00)); // exactly at cap
    }

    #[test]
    fn test_can_afford_exceeds_budget() {
        let tracker = BudgetTracker::new(1.0);
        assert!(!tracker.can_afford(1.01));
    }

    #[test]
    fn test_can_afford_after_spending() {
        let mut tracker = BudgetTracker::new(1.0);
        let pricing = ModelPricing::claude_sonnet();
        // Spend ~$0.06
        tracker
            .record_cost("claude", 10_000, 2_000, &pricing, "test call")
            .unwrap();
        assert!(tracker.can_afford(0.50));
        assert!(!tracker.can_afford(1.00)); // 0.06 + 1.00 > 1.0
    }

    // --- BudgetTracker::record_cost ---

    #[test]
    fn test_record_cost_updates_total() {
        let mut tracker = BudgetTracker::new(25.0);
        let pricing = ModelPricing::claude_sonnet();

        let cost = tracker
            .record_cost("claude-sonnet", 10_000, 2_000, &pricing, "mutation call")
            .unwrap();

        assert!((cost - 0.06).abs() < 0.0001);
        assert!((tracker.total_spent_usd - 0.06).abs() < 0.0001);
        assert_eq!(tracker.records.len(), 1);
        assert_eq!(tracker.records[0].model, "claude-sonnet");
        assert_eq!(tracker.records[0].description, "mutation call");
        assert_eq!(tracker.records[0].input_tokens, 10_000);
        assert_eq!(tracker.records[0].output_tokens, 2_000);
    }

    #[test]
    fn test_record_cost_rejects_over_budget() {
        let mut tracker = BudgetTracker::new(0.05);
        let pricing = ModelPricing::claude_sonnet();

        // This costs ~$0.06 which exceeds the $0.05 cap
        let result = tracker.record_cost("claude", 10_000, 2_000, &pricing, "over budget");
        assert!(result.is_err());
        assert!(
            result.unwrap_err().to_string().contains("Budget exceeded"),
            "error message must mention budget exceeded"
        );
        // Spend must NOT have increased
        assert!((tracker.total_spent_usd - 0.0).abs() < f64::EPSILON);
        assert!(tracker.records.is_empty());
    }

    // --- BudgetTracker::remaining ---

    #[test]
    fn test_remaining_never_negative() {
        let mut tracker = BudgetTracker::new(0.01);
        // Manually set spend above cap to test the floor
        tracker.total_spent_usd = 0.02;
        assert!((tracker.remaining() - 0.0).abs() < f64::EPSILON);
    }

    // --- BudgetTracker::restore_from_experiment_count ---

    #[test]
    fn test_restore_from_experiment_count() {
        let mut tracker = BudgetTracker::new(25.0);
        tracker.restore_from_experiment_count(10, 0.40);
        // 10 experiments * $0.40 = $4.00
        assert!((tracker.total_spent_usd - 4.0).abs() < 0.0001);
        assert!((tracker.remaining() - 21.0).abs() < 0.0001);
    }

    // --- JSON serialization ---

    #[test]
    fn test_json_roundtrip() {
        let mut tracker = BudgetTracker::new(25.0);
        let pricing = ModelPricing::claude_sonnet();
        tracker
            .record_cost("claude", 5_000, 1_000, &pricing, "roundtrip test")
            .unwrap();

        let json = tracker.to_json().unwrap();
        let restored = BudgetTracker::from_json(&json).unwrap();

        assert!((restored.budget_cap_usd - 25.0).abs() < f64::EPSILON);
        assert!((restored.total_spent_usd - tracker.total_spent_usd).abs() < 0.0001);
        assert_eq!(restored.records.len(), 1);
        assert_eq!(restored.records[0].model, "claude");
    }

    // --- File persistence ---

    #[test]
    fn test_save_and_load() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("budget.json");

        let mut tracker = BudgetTracker::new(25.0);
        let pricing = ModelPricing::claude_sonnet();
        tracker
            .record_cost("claude", 5_000, 1_000, &pricing, "save test")
            .unwrap();
        tracker.save(&path).unwrap();

        let loaded = BudgetTracker::load(&path).unwrap().unwrap();
        assert!((loaded.total_spent_usd - tracker.total_spent_usd).abs() < 0.0001);
        assert_eq!(loaded.records.len(), 1);
    }

    #[test]
    fn test_load_nonexistent_returns_none() {
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("nonexistent.json");
        let result = BudgetTracker::load(&path).unwrap();
        assert!(result.is_none());
    }
}

//! Scoring engine for comparing specialist findings against benchmark ground truth.
//!
//! Uses location proximity and keyword overlap to match findings, then computes
//! recall, precision, and weighted composite scores.

use std::collections::HashSet;
use std::fmt;

use forge::autoresearch::benchmarks::{Expected, ExpectedFinding, MustNotFlag};

use super::judge::{ClassificationVerdict, JudgeResult};

/// A finding produced by a specialist agent.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct Finding {
    pub severity: String,
    pub file: String,
    pub line: Option<u32>,
    pub issue: String,
    pub suggestion: String,
}

/// Composite score for a specialist's performance on benchmarks.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct SpecialistScore {
    pub recall: f64,
    pub precision: f64,
    pub actionability: f64,
    pub composite: f64,
}

impl fmt::Display for SpecialistScore {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(
            f,
            "recall={:.1}% precision={:.1}% actionability={:.1}% composite={:.1}%",
            self.recall * 100.0,
            self.precision * 100.0,
            self.actionability * 100.0,
            self.composite * 100.0,
        )
    }
}

/// Parsed location from an expected finding's location string.
#[derive(Debug, Clone, PartialEq)]
pub struct ParsedLocation {
    pub file: Option<String>,
    pub start_line: Option<u32>,
    pub end_line: Option<u32>,
}

const LINE_TOLERANCE: u32 = 5;
const MUST_FIND_OVERLAP_THRESHOLD: f64 = 0.50;
const MUST_NOT_FLAG_OVERLAP_THRESHOLD: f64 = 0.60;

const STOP_WORDS: &[&str] = &[
    "the", "a", "an", "is", "are", "was", "were", "be", "been", "being", "in", "on", "at", "to",
    "for", "of", "with", "and", "or", "but", "not", "this", "that", "it", "its",
];

/// Parse a line range string like `"42-45"` or `"42"` into start/end line numbers.
fn parse_line_range(s: &str) -> (Option<u32>, Option<u32>) {
    if let Some(dash_pos) = s.find('-') {
        let start = s[..dash_pos].parse::<u32>().ok();
        let end = s[dash_pos + 1..].parse::<u32>().ok();
        (start, end)
    } else {
        let line = s.parse::<u32>().ok();
        (line, line)
    }
}

/// Parse a location string like `"code.rs:42-45"`, `"code.rs:42"`, `"line 42-45"`,
/// `"line 42"`, or `""` into a [`ParsedLocation`].
pub fn parse_location(location: &str) -> ParsedLocation {
    let location = location.trim();
    if location.is_empty() {
        return ParsedLocation {
            file: None,
            start_line: None,
            end_line: None,
        };
    }

    // "line 42-45" or "line 42"
    if let Some(line_part) = location.strip_prefix("line ") {
        let (start, end) = parse_line_range(line_part);
        return ParsedLocation {
            file: None,
            start_line: start,
            end_line: end,
        };
    }

    // "file.rs:42-45" or "file.rs:42"
    if let Some(colon_pos) = location.rfind(':') {
        let file = &location[..colon_pos];
        let line_part = &location[colon_pos + 1..];
        let (start, end) = parse_line_range(line_part);
        if start.is_some() {
            return ParsedLocation {
                file: Some(file.to_string()),
                start_line: start,
                end_line: end,
            };
        }
    }

    // Bare filename
    ParsedLocation {
        file: Some(location.to_string()),
        start_line: None,
        end_line: None,
    }
}

/// Tokenize a string: lowercase, split on non-alphanumeric, remove stop words.
fn tokenize(s: &str) -> Vec<String> {
    s.to_lowercase()
        .split(|c: char| !c.is_alphanumeric())
        .filter(|w| !w.is_empty())
        .filter(|w| !STOP_WORDS.contains(w))
        .map(|w| w.to_string())
        .collect()
}

/// Compute keyword overlap between an expected description and a finding description.
///
/// Returns `intersection_count / expected_token_count`, or `0.0` if the expected
/// string has zero non-stop tokens.
pub fn keyword_overlap(expected_desc: &str, finding_desc: &str) -> f64 {
    let expected_tokens: HashSet<String> = tokenize(expected_desc).into_iter().collect();
    if expected_tokens.is_empty() {
        return 0.0;
    }
    let finding_tokens: HashSet<String> = tokenize(finding_desc).into_iter().collect();
    let intersection = expected_tokens.intersection(&finding_tokens).count();
    intersection as f64 / expected_tokens.len() as f64
}

/// Check if a finding's file and line match a parsed location within [`LINE_TOLERANCE`].
fn location_matches(finding: &Finding, loc: &ParsedLocation) -> bool {
    if let Some(ref expected_file) = loc.file
        && finding.file != *expected_file
    {
        return false;
    }
    if let (Some(start), Some(end)) = (loc.start_line, loc.end_line) {
        match finding.line {
            Some(finding_line) => {
                let range_start = start.saturating_sub(LINE_TOLERANCE);
                let range_end = end.saturating_add(LINE_TOLERANCE);
                if finding_line < range_start || finding_line > range_end {
                    return false;
                }
            }
            None => return false,
        }
    }
    true
}

/// Matches specialist findings against benchmark ground truth.
pub struct FindingMatcher;

impl FindingMatcher {
    /// Check if a finding matches an expected finding using location proximity
    /// (±5 lines) AND keyword overlap (>50%). Both must pass when location is present.
    pub fn matches_expected(finding: &Finding, expected: &ExpectedFinding) -> bool {
        let loc = parse_location(&expected.location);
        let has_location = loc.file.is_some() || loc.start_line.is_some();

        let overlap = keyword_overlap(&expected.description, &finding.issue);
        let keyword_match = overlap > MUST_FIND_OVERLAP_THRESHOLD;

        if has_location {
            location_matches(finding, &loc) && keyword_match
        } else {
            keyword_match
        }
    }

    /// Check if a finding matches a must-not-flag entry using keyword overlap (>60%)
    /// OR location match. Either condition triggers a match.
    pub fn matches_must_not_flag(finding: &Finding, must_not: &MustNotFlag) -> bool {
        let overlap = keyword_overlap(&must_not.description, &finding.issue);
        if overlap > MUST_NOT_FLAG_OVERLAP_THRESHOLD {
            return true;
        }

        if let Some(ref loc_str) = must_not.location {
            let loc = parse_location(loc_str);
            if location_matches(finding, &loc) {
                return true;
            }
        }

        false
    }

    /// Count how many findings match at least one must_not_flag entry.
    pub fn count_must_not_flag_hits(findings: &[Finding], must_not_flag: &[MustNotFlag]) -> usize {
        findings
            .iter()
            .filter(|f| {
                must_not_flag
                    .iter()
                    .any(|mnf| Self::matches_must_not_flag(f, mnf))
            })
            .count()
    }

    /// Identify novel findings: those that match neither any must_find nor any
    /// must_not_flag entry. Returns a set of finding indices.
    pub fn identify_novel_findings(findings: &[Finding], expected: &Expected) -> HashSet<usize> {
        findings
            .iter()
            .enumerate()
            .filter(|(_, f)| {
                let matches_must_find = expected
                    .must_find
                    .iter()
                    .any(|ef| Self::matches_expected(f, ef));
                let matches_must_not = expected
                    .must_not_flag
                    .iter()
                    .any(|mnf| Self::matches_must_not_flag(f, mnf));
                !matches_must_find && !matches_must_not
            })
            .map(|(i, _)| i)
            .collect()
    }
}

/// Computes recall, precision, and composite scores.
pub struct Scorer;

impl Scorer {
    /// Score specialist findings against expected outcomes.
    ///
    /// - `recall` = matched_must_finds / total_must_finds (0 must_finds => 1.0)
    /// - `precision` = 1.0 - false_positives / total_findings (0 findings => 1.0)
    /// - `composite` = 0.4 * recall + 0.3 * precision + 0.3 * actionability
    ///
    /// When `judge_result` is `Some`, actionability is the average of the judge's
    /// actionability scores, and novel findings classified as false_positive reduce
    /// precision. When `None`, actionability defaults to 0.5 and novel findings are
    /// assumed true_positive.
    pub fn score(
        findings: &[Finding],
        expected: &Expected,
        judge_result: Option<&JudgeResult>,
    ) -> SpecialistScore {
        let total_must_finds = expected.must_find.len();
        let matched = expected
            .must_find
            .iter()
            .filter(|ef| {
                findings
                    .iter()
                    .any(|f| FindingMatcher::matches_expected(f, ef))
            })
            .count();
        let recall = if total_must_finds == 0 {
            1.0
        } else {
            matched as f64 / total_must_finds as f64
        };

        let precision = Self::compute_precision_with_judge(findings, expected, judge_result);

        let actionability = match judge_result {
            Some(jr) if !jr.actionability_scores.is_empty() => {
                let sum: f64 = jr.actionability_scores.iter().map(|s| s.score).sum();
                sum / jr.actionability_scores.len() as f64
            }
            _ => 0.5,
        };

        let composite = 0.4 * recall + 0.3 * precision + 0.3 * actionability;

        SpecialistScore {
            recall,
            precision,
            actionability,
            composite,
        }
    }

    /// Compute precision accounting for judge classifications of novel findings.
    ///
    /// False positives come from two sources:
    /// 1. must_not_flag hits (always counted, regardless of judge)
    /// 2. Novel findings classified as false_positive by the judge (only when judge present)
    ///
    fn compute_precision_with_judge(
        findings: &[Finding],
        expected: &Expected,
        judge_result: Option<&JudgeResult>,
    ) -> f64 {
        let total_findings = findings.len();
        if total_findings == 0 {
            return 1.0;
        }

        let must_not_flag_fps =
            FindingMatcher::count_must_not_flag_hits(findings, &expected.must_not_flag);

        let judge_fps = match judge_result {
            Some(jr) => {
                let novel_indices = FindingMatcher::identify_novel_findings(findings, expected);
                let novel_finding_ids: HashSet<String> =
                    novel_indices.iter().map(|i| i.to_string()).collect();
                jr.classifications
                    .iter()
                    .filter(|c| {
                        novel_finding_ids.contains(&c.finding_id)
                            && c.verdict == ClassificationVerdict::FalsePositive
                    })
                    .count()
            }
            None => 0,
        };

        let total_fps = must_not_flag_fps + judge_fps;
        let precision = 1.0 - (total_fps as f64 / total_findings as f64);
        precision.max(0.0)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // --- Location parsing tests ---

    #[test]
    fn test_parse_location_file_and_line_range() {
        let loc = parse_location("code.rs:42-45");
        assert_eq!(loc.file, Some("code.rs".to_string()));
        assert_eq!(loc.start_line, Some(42));
        assert_eq!(loc.end_line, Some(45));
    }

    #[test]
    fn test_parse_location_file_and_single_line() {
        let loc = parse_location("issues.rs:70");
        assert_eq!(loc.file, Some("issues.rs".to_string()));
        assert_eq!(loc.start_line, Some(70));
        assert_eq!(loc.end_line, Some(70));
    }

    #[test]
    fn test_parse_location_line_only() {
        let loc = parse_location("line 42-45");
        assert_eq!(loc.file, None);
        assert_eq!(loc.start_line, Some(42));
        assert_eq!(loc.end_line, Some(45));
    }

    #[test]
    fn test_parse_location_empty_string() {
        let loc = parse_location("");
        assert_eq!(loc.file, None);
        assert_eq!(loc.start_line, None);
        assert_eq!(loc.end_line, None);
    }

    #[test]
    fn test_parse_location_single_line_only() {
        let loc = parse_location("line 42");
