pub fn expand_specialists(input: &str) -> Vec<String> {
    let trimmed = input.trim();
    if trimmed.eq_ignore_ascii_case("all") {
        return BUILT_IN_SPECIALISTS
            .iter()
            .map(|s| (*s).to_string())
            .collect();
    }
    trimmed
        .split(',')
        .map(|s| s.trim().to_string())
        .filter(|s| !s.is_empty())
        .collect()
}

